ruleContent.content:
@js:
function d(a, b) {
    b = java.md5Encode(b);
    var d = b.substring(0, 16);
    var e = b.substring(16);
    return java.aesBase64DecodeToString(
        a, 
        e, 
        "AES/CBC/PKCS5Padding", 
        d
    );
}

eval(result.match(/(d\("[\s\S]+?"\))\)/)[1]);

ruleToc.chapterList:
class.BCsectionTwo-top-chapter@li
<js>
list = result.toArray();
s = /originalOrder = .*?;/.test(src)?eval(src.match(/originalOrder = (.*?);/)[1]):result;
l = [];
if(/<li.*?"\d+" .*?-[^"]+="\d+">/.test(result)){
	num = String(result).match(/<li.*?"\d+" (.*?-[^"]+)="\d+">/)[1];
	l = list.sort((a,b)=>a.attr(num)-b.attr(num));
	}else{
for(i in list){ l[s[i]] = list[i]};
}
l.join("")
</js>
