@js:




//分类样式(0/1)
//0: 排序-类型-状态
//1: 类型-排序-状态

style = 0



sort=[];
push=(title,url,type)=> sort.push({
		title: title,
		url: url,
		style: {
				layout_flexGrow: 1,
				layout_flexBasisPercent: type
			}
	});
$$=(a,b,c)=> `https://m.shuhaige.net/shuku/${b}_${a}_${c}_{{page}\}.html`;


a=b=c=0;
d=(title,a,b,c)=> push("༺ˇ»`ʚ \ud83d\udd39"+title+"\ud83d\udd39 ɞ´«ˇ༻",$$(a,b,c),1);


arra=["全部","玄幻","奇幻","武侠","都市","历史","军事","悬疑","游戏","科幻","体育","古言","现言","幻言","仙侠","青春","穿越","女生","其它"];


arrb=[["默认","0"],["总点击","allvisit"],["月点击","monthvisit"],["周点击","weekvisit"],["日点击","dayvisit"],["总推荐","allvote"],["月推荐","monthvote"],["周推荐","weekvote"],["日推荐","dayvote"],["总收藏","goodnum"],["字数","size"],["最新入库","postdate"]];
arrc=(title,a,b)=>[""+title+"","连载","全本"]
		.map((title,c)=>{
		if(c) c+='';
		else c='0';
		push(title,$$(a,b,c),0.25);
			});


if(style==0){
		arrb.map([title,b]=>{
				d(title,a,b,c);
				arra.map((title,a)=>arrc(title,a,b));
			});
	}
else{
		arra.map((title,a)=>{
				d(title,a,b,c);
				arrb.map([title,b]=>arrc(title,a,b));
			});
	}
JSON.stringify(sort);

