function getComments(type, content, bid, cid, version) {
    // 主函数
    const { java, cache } = this;
    //let date = String(Date.now()).match(/(\d{6}$)/)[1];
    try {
        let comments;
        let comcont = content.split("\n");
        if (type == "fq") {
            comments = java.ajax(`{{source.bookSourceUrl}}fqdlsj?item_id=${cid}&version=${version}`);
            //java.log(comments);
            let raw = JSON.parse(comments).data.data;
            Object.keys(raw).forEach((x) => {
                cache.putMemory(`fq-${bid}-${cid}-${x}-text`, comcont[x]);
                comcont[x] += `<img src ="${this.createSvg(type, raw[x].count, "red", bid, cid, x, version)}">`;
            });
            return comcont.join("\n");
        } else {
            comments = java.ajax(`{{source.bookSourceUrl}}qmdlsj?book_id=${bid}&chapter_id=${cid}`);
            java.log(comments);
            let raw = JSON.parse(comments).data.chapters[0].bubbles;
            raw.forEach((x, i) => {
                cache.putMemory(`qm-${bid}-${cid}-${i}-text`, comcont[i]);
                if (x.c > 0) {
                    comcont[i] += `<img src ="${this.createSvg(type, x.c, "red", bid, cid, x.p)}">`;
                }
            });
            return comcont.join("\n");
        }
    } catch (e) {
        java.log(e);
        return content;
    }
}

function createSvg(type, number, color, bid, cid, para, version) {
    let displayText = number > 99 ? "99+" : number;
    let date = Date.now().toString(); // 内部生成时间戳

    let svg = `<svg width="1000" height="800" xmlns="http://www.w3.org/2000/svg">
    <rect x="25" y="25" width="950" height="750" rx="250" ry="250" fill="none" stroke="${color}" stroke-width="25"/>
    <text x="510" y="650" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="30" fill="#000000">刷新图片查看段评</text>
    <text x="510" y="565" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="425" fill="${color}">${displayText}</text>
</svg>
`;
    let encodedSvg = this.java.base64Encode(svg);
    return `data:image/svg+xml;base64,${encodedSvg},{'type':'fq','js':'showCmt("${type}","${bid}", "${cid}", "${para}", "${version}", ${date})'}`;
}

function showCmt(type, bid, cid, para, version, date) {
    const { java, cache } = this;
    if (type == "fq") {
        var mname = `fq-${bid}-${cid}-${para}`;
        var cname = "item_id";
        var pname = "para";
    } else if (type == "qm") {
        var mname = `qm-${bid}-${cid}-${para}`;
        var cname = "chapter_id";
        var pname = "paragraph_id";
    }

    let load = (cache.getFromMemory(mname) ?? "-").split("-");
    if (load[0] != "1" || load[1] != date) {
        cache.putMemory(mname, "1-" + date);
        //java.toast("跳过加载");
        return;
    }
    let apiUrl = `{{source.bookSourceUrl}}${type}dlpl?${cname}=${cid}&book_id=${bid}&${pname}=${para}&version=${version}&key={{Map("密钥")}}`;
    let title = cache.getFromMemory(mname + "-text") ?? "段评";

    java.startBrowser(apiUrl, title);
}

